        border: 1px dashed #00f2fe; 
        padding: 10px; border-radius: 5px; 
        font-size: 0.9em; color: #a78bfa; margin-bottom: 20px; 
    }

    /* Tabla */
    .cyber-table { width: 100%; border-collapse: collapse; margin-top: 15px; text-align: center; }
    .cyber-table th { color: #00f2fe; padding: 10px; border-bottom: 2px solid #00f2fe; font-size: 0.8em; }
    .cyber-table td { padding: 12px; border-bottom: 1px solid rgba(0, 242, 254, 0.1); }

    /* Inputs con Validación Dinámica */
    .cyber-input { 
        width: 55px; 
        background: #0d111a; 
        border: 2px solid #4facfe; 
        color: #fff; 
        text-align: center; 
        padding: 8px; 
        border-radius: 5px; 
        font-weight: bold;
        transition: all 0.3s;
    }

    /* Estados de validación */
    .val-correct { border-color: #00ff00 !important; box-shadow: 0 0 10px #00ff00; background: rgba(0, 255, 0, 0.1) !important; }
    .val-incorrect { border-color: #ff0000 !important; box-shadow: 0 0 10px #ff0000; background: rgba(255, 0, 0, 0.1) !important; }

    /* Mensaje de Éxito */
    #success-msg { 
        display: none; 
        margin-top: 20px; 
        padding: 15px; 
        background: rgba(0, 255, 0, 0.2); 
        border: 1px solid #00ff00; 
        color: #00ff00; 
        text-align: center; 
        font-weight: bold; 
        border-radius: 5px;
        animation: pulse 1.5s infinite;
    }

    @keyframes pulse {
        0% { opacity: 0.7; }
        50% { opacity: 1; }
        100% { opacity: 0.7; }
    }
</style>
<div class="cyber-panel">
<div class="cyber-header">🛡️ ALGORITMO: CONTROL DE ENGAGEMENT</div>
<div class="cyber-content">
<p style="font-size: 0.9em;"><strong>Misión:</strong> El algoritmo de TikTok ha detectado 20 influencers usando el tag #MirrorCorp. Tabula las menciones para entender el patrón.</p>
<div class="cyber-data-box">> DATA_STREAM: [ 0, 1, 2, 1, 0, 1, 3, 1, 2, 1, 0, 1, 1, 2, 0, 1, 2, 1, 3, 1 ]</div>
<table class="cyber-table">
<thead>
<tr>
<th>Menciones ($x_i$)</th>
<th>Frec. Absoluta ($f_i$)</th>
<th>Frec. Acumulada ($F_i$)</th>
</tr>
</thead>
<tbody>
<tr>
<td>0</td>
<td><input type="number" class="cyber-input q-input" data-ans="4" /></td>
<td><input type="number" class="cyber-input q-input" data-ans="4" /></td>
</tr>
<tr>
<td>1</td>
<td><input type="number" class="cyber-input q-input" data-ans="10" /></td>
<td><input type="number" class="cyber-input q-input" data-ans="14" /></td>
</tr>
<tr>
<td>2</td>
<td><input type="number" class="cyber-input q-input" data-ans="4" /></td>
<td><input type="number" class="cyber-input q-input" data-ans="18" /></td>
</tr>
<tr>
<td>3</td>
<td><input type="number" class="cyber-input q-input" data-ans="2" /></td>
<td><input type="number" class="cyber-input q-input" data-ans="20" /></td>
</tr>
<tr style="background: rgba(0, 242, 254, 0.05);">
<td><strong>TOTAL (N)</strong></td>
<td><input type="number" class="cyber-input q-input" data-ans="20" /></td>
<td>---</td>
</tr>
</tbody>
</table>
<div id="success-msg">🔓 ¡CÓDIGO DE ALGORITMO DESCIFRADO! Datos validados correctamente.</div>
</div>
</div>
<p>
<script>
    (function() {
        const inputs = document.querySelectorAll('.q-input');
        const successMsg = document.getElementById('success-msg');

        inputs.forEach(input => {
            input.addEventListener('input', function() {
                const userAns = this.value;
                const correctAns = this.getAttribute('data-ans');

                if (userAns === "") {
                    this.classList.remove('val-correct', 'val-incorrect');
                } else if (userAns === correctAns) {
                    this.classList.add('val-correct');
                    this.classList.remove('val-incorrect');
                } else {
                    this.classList.add('val-incorrect');
                    this.classList.remove('val-correct');
                }

                checkAll();
            });
        });

        function checkAll() {
            let allCorrect = true;
            inputs.forEach(input => {
                if (input.value !== input.getAttribute('data-ans')) {
                    allCorrect = false;
                }
            });

            if (allCorrect) {
                successMsg.style.display = 'block';
            } else {
                successMsg.style.display = 'none';
            }
        }
    })();
</script>
</p>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

