{"ideviceId":"idevice-1775646996540-7cai1ykzm","textInfoDurationInput":"","textInfoDurationTextInput":"Duración","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Agrupamiento","textTextarea":"<style>
    .detective-box { font-family: 'Courier New', monospace; max-width: 700px; margin: 20px auto; background: #0a0a0a; border: 2px solid #00f2fe; border-radius: 10px; padding: 20px; color: #00f2fe; box-shadow: 0 0 15px #00f2fe; }
    .det-title { text-align: center; text-transform: uppercase; font-weight: bold; border-bottom: 1px solid #00f2fe; padding-bottom: 10px; margin-bottom: 20px; }
    .data-stream { background: rgba(0, 242, 254, 0.1); padding: 10px; border-radius: 5px; color: #fff; margin-bottom: 20px; text-align: center; }
    .exercise-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 15px; }
    .det-input { width: 80px; background: #000; border: 1px solid #00f2fe; color: #fff; padding: 5px; text-align: center; border-radius: 4px; }
    .val-correct { border-color: #0f0 !important; box-shadow: 0 0 10px #0f0; background: rgba(0,255,0,0.1) !important; }
    .val-incorrect { border-color: #f00 !important; box-shadow: 0 0 10px #f00; background: rgba(255,0,0,0.1) !important; }
    .success-msg { display:none; color: #0f0; text-align: center; margin-top: 15px; font-weight: bold; }
</style>
<div class="detective-box">
<div class="det-title">🔍 CASO 01: EL POST VIRAL</div>
<p style="font-size: 0.9em; color: #ccc;">Se han analizado los likes de los últimos 10 posts de un influencer. Calcula los parámetros:</p>
<div class="data-stream">&gt; LIKES_RAW: [ 10, 15, 10, 20, 10, 25, 30, 10, 20, 50 ]</div>
<div class="exercise-grid">
<div>Moda ($M_o$): <input type="number" class="det-input q1" data-ans="10" /></div>
<div>Rango ($R$): <input type="number" class="det-input q1" data-ans="40" /></div>
<div>Media ($\bar{x}$): <input type="number" class="det-input q1" data-ans="20" /></div>
<div>$N$ total: <input type="number" class="det-input q1" data-ans="10" /></div>
</div>
<div id="msg1" class="success-msg">🔓 PARÁMETROS VALIDADOS. ACCESO CONCEDIDO.</div>
</div>
<p>
<script>
    (function(){
        const ins = document.querySelectorAll('.q1');
        ins.forEach(i => { i.addEventListener('input', function(){
            if(this.value == this.getAttribute('data-ans')){ this.classList.add('val-correct'); this.classList.remove('val-incorrect'); }
            else if(this.value == ""){ this.classList.remove('val-correct','val-incorrect'); }
            else { this.classList.add('val-incorrect'); this.classList.remove('val-correct'); }
            if(Array.from(ins).every(x => x.value == x.getAttribute('data-ans'))){ document.getElementById('msg1').style.display='block'; }
        });});
    })();
</script>
</p>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

{"ideviceId":"idevice-1775647228043-v06cio6bg","textInfoDurationInput":"","textInfoDurationTextInput":"Duración","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Agrupamiento","textTextarea":"<style>
    .vf-box { font-family: 'Segoe UI', sans-serif; max-width: 700px; margin: 20px auto; background: #0f172a; border: 2px solid #38bdf8; border-radius: 10px; padding: 20px; color: #f1f5f9; box-shadow: 0 0 15px #38bdf8; }
