        text-align: center;
    }
    .exam-content { padding: 30px; }
    .question-block {
        margin-bottom: 25px;
        padding-bottom: 20px;
        border-bottom: 1px dashed #cbd5e1;
    }
    .question-text {
        font-weight: 600;
        color: #0f172a;
        margin-bottom: 15px;
        display: block;
    }
    .option-label {
        display: block;
        padding: 10px;
        margin: 5px 0;
        background: #f1f5f9;
        border-radius: 6px;
        cursor: pointer;
        transition: 0.2s;
    }
    .option-label:hover { background: #e2e8f0; }
    .option-label input { margin-right: 10px; }

    .btn-submit {
        display: block;
        width: 100%;
        padding: 15px;
        background: #2563eb;
        color: white;
        border: none;
        border-radius: 8px;
        font-weight: bold;
        font-size: 1.1em;
        cursor: pointer;
        transition: 0.3s;
    }
    .btn-submit:hover { background: #1d4ed8; }

    #result-area {
        display: none;
        margin-top: 20px;
        padding: 20px;
        border-radius: 8px;
        text-align: center;
        font-weight: bold;
    }
    .feedback-correct { background: #dcfce7; color: #166534; border: 1px solid #166534; }
    .feedback-wrong { background: #fee2e2; color: #991b1b; border: 1px solid #991b1b; }
</style>
<div class="exam-container">
<div class="exam-header">
<h2 style="margin: 0;">📑 SIMULADOR</h2>
<small>Mirror Corp Training. Nivel: Agente Lvl 2.</small></div>
<div class="exam-content">
<div class="question-block"><span class="question-text">1. Dados los datos de uso [ 10, 12, 14, 16, 18 ] con media x̄ = 14. ¿Cuál es la varianza (S²)?</span> <label class="option-label"><input type="radio" name="q1" value="wrong" /> 4</label> <label class="option-label"><input type="radio" name="q1" value="correct" /> 8</label> <label class="option-label"><input type="radio" name="q1" value="wrong" /> 14</label> <label class="option-label"><input type="radio" name="q1" value="wrong" /> 2.82</label></div>
<div class="question-block"><span class="question-text">2. Si la varianza de los likes de una muestra es 49. ¿Cuál es la Desviación Típica (S)?</span> <label class="option-label"><input type="radio" name="q2" value="wrong" /> 7 likes²</label> <label class="option-label"><input type="radio" name="q2" value="correct" /> 7 likes</label> <label class="option-label"><input type="radio" name="q2" value="wrong" /> 24.5 likes</label> <label class="option-label"><input type="radio" name="q2" value="wrong" /> 2401 likes</label></div>
<div class="question-block"><span class="question-text">3. Grupo A: x̄=100, S=15 | Grupo B: x̄=20, S=5. ¿Qué grupo es más heterogéneo (mayor dispersión)?</span> <label class="option-label"><input type="radio" name="q3" value="wrong" /> Grupo A (CV = 15%)</label> <label class="option-label"><input type="radio" name="q3" value="correct" /> Grupo B (CV = 25%)</label> <label class="option-label"><input type="radio" name="q3" value="wrong" /> Son iguales porque el rango es el mismo</label> <label class="option-label"><input type="radio" name="q3" value="wrong" /> Grupo A porque su Desviación Típica es mayor (15 > 5)</label></div>
<div class="question-block"><span class="question-text">4. Si todos los alumnos de una clase obtienen exactamente un 7.5 en el simulador, ¿cuánto vale la Varianza y el CV?</span> <label class="option-label"><input type="radio" name="q4" value="correct" /> S² = 0 y CV = 0%</label> <label class="option-label"><input type="radio" name="q4" value="wrong" /> S² = 7.5 y CV = 100%</label> <label class="option-label"><input type="radio" name="q4" value="wrong" /> S² = 0 y CV = 7.5%</label> <label class="option-label"><input type="radio" name="q4" value="wrong" /> No se pueden calcular si no hay variación</label></div>
<div class="question-block" style="border: none;"><span class="question-text">5. Calcula el Coeficiente de Variación si S² = 144 y x̄ = 60.</span> <label class="option-label"><input type="radio" name="q5" value="wrong" /> 2.4%</label> <label class="option-label"><input type="radio" name="q5" value="wrong" /> 240%</label> <label class="option-label"><input type="radio" name="q5" value="correct" /> 20%</label> <label class="option-label"><input type="radio" name="q5" value="wrong" /> 12%</label></div>
<button class="btn-submit" onclick="checkExam()">FINALIZAR Y CORREGIR</button>
<div id="result-area"></div>
</div>
</div>
<p>
<script>
    function checkExam() {
        const totalQuestions = 5;
        let score = 0;

        // Verificar cada pregunta
        for(let i=1; i<=totalQuestions; i++) {
            const selected = document.querySelector(`input[name="q${i}"]:checked`);
            if(selected && selected.value === "correct") {
                score++;
            }
        }

        const resultArea = document.getElementById('result-area');
        resultArea.style.display = "block";

        if(score >= 4) {
            resultArea.className = "feedback-correct";
            resultArea.innerHTML = `⭐ ¡EXCELENTE! Has acertado ${score} de ${totalQuestions}. Estás preparado para el examen de Mirror Corp.`;
        } else if (score >= 3) {
            resultArea.className = "feedback-correct";
            resultArea.innerHTML = `✔️ BIEN. Has acertado ${score} de ${totalQuestions}. Repasa los fallos antes de la prueba real.`;
        } else {
            resultArea.className = "feedback-wrong";
            resultArea.innerHTML = `❌ NECESITAS REPASAR. Solo has acertado ${score} de ${totalQuestions}. Revisa las fórmulas de S² y CV.`;
        }
    }
</script>
</p>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

