    else { document.getElementById('feedback_p4').innerHTML = "❌ Revisa la teoría de interpolación."; }
}
</script>
</p>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

{"ideviceId":"idevice-1775649097819-dyilh8tyg","textInfoDurationInput":"","textInfoDurationTextInput":"Duración","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Agrupamiento","textTextarea":"<div style="font-family: sans-serif; max-width: 700px; margin: 20px auto; background: #f8fafc; border: 2px solid #6366f1; border-radius: 10px; padding: 20px;">
<h4 style="color: #6366f1; margin-top: 0;">2. EQUIVALENCIAS CRÍTICAS</h4>
<p>Une cada Cuartil con su Percentil equivalente:</p>
<div style="line-height: 2;">$Q_2$ (Mediana) equivale al Percentil: <input type="number" id="p_eq1" placeholder="?" style="width: 50px;" /> <br />$Q_3$ (Cuartil superior) equivale al Percentil: <input type="number" id="p_eq2" placeholder="?" style="width: 50px;" /></div>
