        border-radius: 50%;
        animation: blink SDA-blink 1.5s infinite;
        box-shadow: 0 0 10px #38bdf8;
    }

    /* Contenido */
    .sda-content { padding: 30px; }

    /* Bloque de Introducción de Misión */
    .mission-brief {
        background: rgba(30, 41, 59, 0.4);
        border-left: 4px solid #38bdf8;
        padding: 15px 20px;
        border-radius: 4px;
        margin-bottom: 25px;
        color: #cbd5e1;
        line-height: 1.6;
    }

    /* Grid de Protocolos Operativos */
    .protocol-grid {
