    .protocol-card {
        background: rgba(15, 23, 42, 0.8);
        border: 1px solid #1e293b;
        border-radius: 6px;
        padding: 20px;
        transition: 0.3s;
    }
    .protocol-card:hover {
        border-color: #38bdf8;
        background: rgba(30, 41, 59, 0.6);
        transform: translateY(-2px);
    }
    .protocol-title {
        font-size: 1.1em;
        font-weight: bold;
        color: #ffffff;
        margin-bottom: 15px;
        display: flex;
        align-items: center;
    }
    .protocol-num {
        color: #38bdf8;
        margin-right: 10px;
    }
    .protocol-list {
        font-size: 0.9em;
        padding-left: 18px;
        color: #cbd5e1;
        margin: 0;
        line-height: 1.6;
    }
    .protocol-list li { margin-bottom: 8px; }

    /* Alerta de Detección de Anomalías */
    .anomaly-alert {
        background: rgba(239, 68, 68, 0.1); /* Fondo rojo muy suave */
        border: 1px dashed #ef4444; /* Borde rojo neón */
        padding: 18px;
        border-radius: 8px;
        display: flex;
        align-items: flex-start;
        color: #fca5a5;
    }
    .alert-icon {
        color: #ef4444;
        font-size: 1.6em;
        margin-right: 15px;
        margin-top: -3px;
        animation: blink 1s infinite;
    }
    .alert-text { font-size: 0.9em; line-height: 1.5; }
    .alert-text strong { color: #fecaca; }

    /* Pie de página de Estado */
    .sda-footer {
        background: #111827;
