        border-top: 1px solid #1e293b;
        font-size: 0.8em;
        color: #64748b;
        text-align: right;
        font-style: italic;
    }

    /* Animaciones */
    @keyframes blink {
        0%, 100% { opacity: 1; }
        50% { opacity: 0.4; }
